/**
 * Retrieves hailort library version.
 * 
 * @param version [out]         Will be filled with hailort library version.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_get_library_version(hailo_version_t version);

/**
 * Returns a string format of \ status.
 * 
 * @param status [in]         A ::hailo_status to be converted to string format.
 * @return Upon success, returns \ status as a string format. Otherwise, returns \a nullptr.
 */
public static native @Cast("const char*") BytePointer hailo_get_status_message(@Cast("hailo_status") int status);

