/**
 * Change throttling state of temperature protection and overcurrent protection components.
 * In case that change throttling state of temperature protection didn't succeed,
 * the change throttling state of overcurrent protection is executed.
 *
 * @param device [in]            A ::hailo_device object.
 * @param should_activate [in]   Should be true to enable or false to disable.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns an ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_set_throttling_state(_hailo_device device, @Cast("bool") boolean should_activate);

/**
 * Get current throttling state of temperature protection and overcurrent protection components.
 * If any throttling is enabled, the function return true.
 *
 * @param device [in]            A ::hailo_device object.
 * @param is_active [out]        A pointer to the temperature protection or overcurrent protection components throttling state: true if active, false otherwise.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns an ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_get_throttling_state(_hailo_device device, @Cast("bool*") BoolPointer is_active);
public static native @Cast("hailo_status") int hailo_get_throttling_state(_hailo_device device, @Cast("bool*") boolean[] is_active);

