/** \defgroup group_power_measurement_functions Power measurement functions
 *  \{
 */

/**
 * Perform a single power measurement.
 * 
 * @param device [in]             A ::hailo_device object.
 * @param dvm [in]                Which DVM will be measured. Default (::HAILO_DVM_OPTIONS_AUTO) will be different according to the board: <br>
 *                                 - Default (::HAILO_DVM_OPTIONS_AUTO) for EVB is an approximation to the total power consumption of the chip in PCIe setups.
 *                                 It sums ::HAILO_DVM_OPTIONS_VDD_CORE, ::HAILO_DVM_OPTIONS_MIPI_AVDD and ::HAILO_DVM_OPTIONS_AVDD_H.
 *                                 Only ::HAILO_POWER_MEASUREMENT_TYPES__POWER can measured with this option.
 *                                 - Default (::HAILO_DVM_OPTIONS_AUTO) for platforms supporting current monitoring (such as M.2 and mPCIe): OVERCURRENT_PROTECTION.
 * @param measurement_type [in]   The type of the measurement. Choosing ::HAILO_POWER_MEASUREMENT_TYPES__AUTO
 *                                 will select the default value according to the supported features.
 * @param measurement [out]        The measured value. Measured units are determined due to
 *                                 ::hailo_power_measurement_types_t.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_power_measurement(_hailo_device device, @Cast("hailo_dvm_options_t") int dvm,
    @Cast("hailo_power_measurement_types_t") int measurement_type, @Cast("float32_t*") FloatPointer measurement);
public static native @Cast("hailo_status") int hailo_power_measurement(_hailo_device device, @Cast("hailo_dvm_options_t") int dvm,
    @Cast("hailo_power_measurement_types_t") int measurement_type, @Cast("float32_t*") FloatBuffer measurement);
public static native @Cast("hailo_status") int hailo_power_measurement(_hailo_device device, @Cast("hailo_dvm_options_t") int dvm,
    @Cast("hailo_power_measurement_types_t") int measurement_type, @Cast("float32_t*") float[] measurement);

/**
 * Start performing a long power measurement.
 * 
 * @param device [in]               A ::hailo_device object.
 * @param averaging_factor [in]     Number of samples per time period, sensor configuration value.
 * @param sampling_period [in]      Related conversion time, sensor configuration value.
 *                                   The sensor samples the power every sampling_period {us} and averages every
 *                                   averaging_factor samples. The sensor provides a new value every: (2 * sampling_period * averaging_factor) {ms}.
 *                                   The firmware wakes up every interval_milliseconds {ms} and checks the sensor.
 *                                   If there is a new value to read from the sensor, the firmware reads it.
 *                                   Note that the average calculated by the firmware is 'average of averages',
 *                                   because it averages values that have already been averaged by the sensor.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_start_power_measurement(_hailo_device device,
    @Cast("hailo_averaging_factor_t") int averaging_factor, @Cast("hailo_sampling_period_t") int sampling_period);

/**
 * Set parameters for long power measurement.
 * 
 * @param device [in]             A ::hailo_device object.
 * @param buffer_index [in]       A ::hailo_measurement_buffer_index_t represents the buffer on the firmware the data would be saved at.
 *                                 Should match the one passed to ::hailo_get_power_measurement.
 * @param dvm [in]                Which DVM will be measured. Default (::HAILO_DVM_OPTIONS_AUTO) will be different according to the board: <br>
 *                                 - Default (::HAILO_DVM_OPTIONS_AUTO) for EVB is an approximation to the total power consumption of the chip in PCIe setups.
 *                                 It sums ::HAILO_DVM_OPTIONS_VDD_CORE, ::HAILO_DVM_OPTIONS_MIPI_AVDD and ::HAILO_DVM_OPTIONS_AVDD_H.
 *                                 Only ::HAILO_POWER_MEASUREMENT_TYPES__POWER can measured with this option.
 *                                 - Default (::HAILO_DVM_OPTIONS_AUTO) for platforms supporting current monitoring (such as M.2 and mPCIe): OVERCURRENT_PROTECTION.
 * @param measurement_type [in]   The type of the measurement. Choosing ::HAILO_POWER_MEASUREMENT_TYPES__AUTO
 *                                 will select the default value according to the supported features.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_set_power_measurement(_hailo_device device, @Cast("hailo_measurement_buffer_index_t") int buffer_index,
    @Cast("hailo_dvm_options_t") int dvm, @Cast("hailo_power_measurement_types_t") int measurement_type);

/**
 * Read measured power from a long power measurement
 * 
 * @param device [in]                A ::hailo_device object.
 * @param buffer_index [in]          A ::hailo_measurement_buffer_index_t represents the buffer on the firmware the data would be saved at.
 *                                    Should match the one passed to ::hailo_set_power_measurement.
 * @param should_clear [in]          Flag indicating if the results saved at the firmware will be deleted after reading.
 * @param measurement_data [out]      The measurement data, ::hailo_power_measurement_data_t. Measured units are
 *                                    determined due to ::hailo_power_measurement_types_t passed to ::hailo_set_power_measurement
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_get_power_measurement(_hailo_device device, @Cast("hailo_measurement_buffer_index_t") int buffer_index, @Cast("bool") boolean should_clear,
     hailo_power_measurement_data_t measurement_data);

/**
 * Stop performing a long power measurement.
 * 
 * @param device [in]             A ::hailo_device object.
 * @return Upon success, returns ::HAILO_SUCCESS. Otherwise, returns a ::hailo_status error.
 */
public static native @Cast("hailo_status") int hailo_stop_power_measurement(_hailo_device device);

/** \} */ // end of group_power_measurement_functions

